function randFrom(arr) {
  return arr[Math.floor(Math.random() * arr.length)];
}

function generateReview(category, productName, sentiment) {
  const reviewText =
    sentiment === "satisfied"   ? randFrom(POSITIVE_REVIEWS) :
    sentiment === "neutral"     ? randFrom(NEUTRAL_REVIEWS)  :
                                  randFrom(NEGATIVE_REVIEWS);
  const rating =
    sentiment === "satisfied"   ? Math.floor(Math.random() * 2) + 4 :  // 4 or 5
    sentiment === "neutral"     ? 3 :
                                  Math.floor(Math.random() * 2) + 1;   // 1 or 2

  const daysAgo = Math.floor(Math.random() * 90);
  const date = new Date(Date.now() - daysAgo * 86400000);

  return {
    id: Math.random().toString(36).substr(2, 9),
    customer: randFrom(INDIAN_NAMES),
    category,
    product: productName,
    sentiment,
    rating,
    review: reviewText,
    date: date.toLocaleDateString("en-IN"),
    verified: Math.random() > 0.2,
  };
}

// Generate 500+ reviews with realistic distribution per category
function generateAllFeedback() {
  const allReviews = [];
  const categories = Object.keys(PRODUCT_NAMES);

  categories.forEach(category => {
    const products = PRODUCT_NAMES[category];
    products.forEach(product => {
      // Each product gets ~15 reviews
      const counts = {
        satisfied: Math.floor(Math.random() * 5) + 7,  // 7-11
        neutral:   Math.floor(Math.random() * 3) + 2,  // 2-4
        dissatisfied: Math.floor(Math.random() * 3) + 1, // 1-3
      };
      Object.entries(counts).forEach(([sentiment, count]) => {
        for (let i = 0; i < count; i++) {
          allReviews.push(generateReview(category, product, sentiment));
        }
      });
    });
  });

  return allReviews;
}

export const FEEDBACK_DATA = generateAllFeedback();

// Summary stats per category
export function getCategorySentiment() {
  const cats = {};
  FEEDBACK_DATA.forEach(r => {
    if (!cats[r.category]) cats[r.category] = { satisfied:0, neutral:0, dissatisfied:0, total:0 };
    cats[r.category][r.sentiment]++;
    cats[r.category].total++;
  });
  return Object.entries(cats).map(([cat, counts]) => ({
    cat,
    satisfied:    counts.satisfied,
    neutral:      counts.neutral,
    dissatisfied: counts.dissatisfied,
    total:        counts.total,
    score: Math.round((counts.satisfied / counts.total) * 100),
  }));
}

// Per product summary
export function getProductSentiment(category) {
  const prods = {};
  FEEDBACK_DATA.filter(r => r.category === category).forEach(r => {
    if (!prods[r.product]) prods[r.product] = { satisfied:0, neutral:0, dissatisfied:0, total:0, reviews:[] };
    prods[r.product][r.sentiment]++;
    prods[r.product].total++;
    prods[r.product].reviews.push(r);
  });
  return Object.entries(prods).map(([product, data]) => ({
    product,
    ...data,
    score: Math.round((data.satisfied / data.total) * 100),
  }));
}