import { useState, useEffect } from "react";
import { PieChart, Pie, Cell, Tooltip, Legend, ResponsiveContainer } from "recharts";
import { FEEDBACK_DATA, getCategorySentiment, getProductSentiment } from "../data/feedbackData";

const COLORS = {
  satisfied:    "#2DD4A0",
  neutral:      "#FF9F1C",
  dissatisfied: "#F4476B",
};

export default function Sentiment({ T }) {
  const [selectedCat, setSelectedCat]     = useState("electronics");
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [aiInsight, setAiInsight]         = useState("");
  const [loadingAI, setLoadingAI]         = useState(false);
  const [visibleReviews, setVisibleReviews] = useState(5);

  const categorySentiment = getCategorySentiment();
  const productSentiment  = getProductSentiment(selectedCat);
  const selectedProductData = selectedProduct
    ? productSentiment.find(p => p.product === selectedProduct)
    : null;

  // Reviews to show in table
  const tableReviews = selectedProductData
    ? selectedProductData.reviews.slice(0, visibleReviews)
    : FEEDBACK_DATA.filter(r => r.category === selectedCat).slice(0, visibleReviews);

  // Pie data for selected category
  const catData = categorySentiment.find(c => c.cat === selectedCat);
  const pieData = catData ? [
    { name: "Satisfied",    value: catData.satisfied    },
    { name: "Neutral",      value: catData.neutral      },
    { name: "Dissatisfied", value: catData.dissatisfied },
  ] : [];

  // Claude API semantic analysis
  async function runSemanticAnalysis() {
    setLoadingAI(true);
    setAiInsight("");
    const reviews = tableReviews.map(r => `"${r.review}" (${r.sentiment}, ★${r.rating})`).join("\n");
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          messages: [{
            role: "user",
            content: `You are a retail analytics AI. Analyze these customer reviews for ${selectedProduct || selectedCat} and provide:
1. Overall sentiment summary (2 sentences)
2. Top 2 specific complaints
3. Top 2 specific praises  
4. One actionable business recommendation

Reviews:
${reviews}

Keep response concise and business-focused. Use INR context (Indian market).`,
          }],
        }),
      });
      const data = await res.json();
      setAiInsight(data.content?.[0]?.text || "Analysis unavailable.");
    } catch {
      setAiInsight("Could not connect to AI. Check your API key.");
    }
    setLoadingAI(false);
  }

  return (
    <div>
      {/* ── Category selector ── */}
      <div style={{ display:"flex", gap:8, marginBottom:22 }}>
        {categorySentiment.map(c => (
          <button key={c.cat} onClick={() => { setSelectedCat(c.cat); setSelectedProduct(null); setVisibleReviews(5); }}
            style={{
              background: selectedCat===c.cat ? T.brand : T.panel,
              border: `1px solid ${selectedCat===c.cat ? T.brand : T.border}`,
              borderRadius:10, padding:"8px 16px", cursor:"pointer",
              color: selectedCat===c.cat ? "#fff" : T.text,
              fontFamily:"'Sora',sans-serif", fontSize:11, fontWeight:600,
              textTransform:"capitalize", transition:"all 0.2s",
            }}>
            {c.cat} · {c.score}% 😊
          </button>
        ))}
      </div>

      {/* ── Top row: Pie + Category scores ── */}
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:18, marginBottom:18 }}>

        {/* Pie chart */}
        <div style={{ background:T.panel, border:`1px solid ${T.border}`, borderRadius:14, padding:22 }}>
          <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:16 }}>
            <div style={{ width:3, height:18, background:T.brand, borderRadius:2 }} />
            <span style={{ fontSize:12, fontWeight:700, letterSpacing:"0.08em", textTransform:"uppercase", color:T.text }}>
              Sentiment Distribution · {selectedCat}
            </span>
          </div>
          <ResponsiveContainer width="100%" height={240}>
            <PieChart>
              <Pie data={pieData} cx="50%" cy="50%" outerRadius={90} dataKey="value" label={({ name, percent }) => `${name} ${(percent*100).toFixed(0)}%`} labelLine={false}>
                {pieData.map((entry, i) => (
                  <Cell key={i} fill={Object.values(COLORS)[i]} />
                ))}
              </Pie>
              <Tooltip formatter={(val) => [`${val} reviews`]} contentStyle={{ background:T.panel, border:`1px solid ${T.border}`, borderRadius:8, fontFamily:"'Sora',sans-serif" }} />
              <Legend wrapperStyle={{ fontSize:11, color:T.muted }} />
            </PieChart>
          </ResponsiveContainer>
        </div>

        {/* Category scores */}
        <div style={{ background:T.panel, border:`1px solid ${T.border}`, borderRadius:14, padding:22 }}>
          <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:16 }}>
            <div style={{ width:3, height:18, background:T.brand, borderRadius:2 }} />
            <span style={{ fontSize:12, fontWeight:700, letterSpacing:"0.08em", textTransform:"uppercase", color:T.text }}>All Categories</span>
          </div>
          <div style={{ display:"flex", flexDirection:"column", gap:14 }}>
            {categorySentiment.map(c => (
              <div key={c.cat} onClick={() => { setSelectedCat(c.cat); setSelectedProduct(null); }} style={{ cursor:"pointer" }}>
                <div style={{ display:"flex", justifyContent:"space-between", marginBottom:5 }}>
                  <span style={{ fontSize:12, color:T.text, fontWeight:600, textTransform:"capitalize" }}>{c.cat}</span>
                  <span style={{ fontSize:11, fontWeight:700, color: c.score>70?COLORS.satisfied:c.score>50?COLORS.neutral:COLORS.dissatisfied }}>
                    {c.score}% satisfied · {c.total} reviews
                  </span>
                </div>
                <div style={{ height:6, background:T.dimmed, borderRadius:3 }}>
                  <div style={{ height:"100%", width:`${c.score}%`, background: c.score>70?COLORS.satisfied:c.score>50?COLORS.neutral:COLORS.dissatisfied, borderRadius:3, transition:"width 0.6s" }} />
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ── Product breakdown ── */}
      <div style={{ background:T.panel, border:`1px solid ${T.border}`, borderRadius:14, padding:22, marginBottom:18 }}>
        <div style={{ display:"flex", alignItems:"center", gap:10, marginBottom:16 }}>
          <div style={{ width:3, height:18, background:T.brand, borderRadius:2 }} />
          <span style={{ fontSize:12, fontWeight:700, letterSpacing:"0.08em", textTransform:"uppercase", color:T.text }}>
            Product Sentiment · {selectedCat}
          </span>
        </div>
        <table style={{ width:"100%", borderCollapse:"collapse" }}>
          <thead>
            <tr style={{ borderBottom:`1px solid ${T.border}` }}>
              {["Product","Score","😊 Satisfied","😐 Neutral","😞 Dissatisfied","Reviews","Action"].map(h => (
                <th key={h} style={{ padding:"8px 12px", textAlign:"left", color:T.muted, fontSize:10, fontWeight:600, letterSpacing:"0.06em" }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {productSentiment.sort((a,b) => b.score-a.score).map(p => (
              <tr key={p.product} onClick={() => setSelectedProduct(p.product === selectedProduct ? null : p.product)}
                style={{ borderBottom:`1px solid ${T.dimmed}`, cursor:"pointer", background: selectedProduct===p.product ? `${T.brand}11` : "transparent", transition:"background 0.15s" }}>
                <td style={{ padding:"10px 12px", fontWeight:600, color:T.text, fontSize:11 }}>{p.product}</td>
                <td style={{ padding:"10px 12px" }}>
                  <span style={{ fontWeight:700, color: p.score>70?COLORS.satisfied:p.score>50?COLORS.neutral:COLORS.dissatisfied }}>
                    {p.score}%
                  </span>
                </td>
                <td style={{ padding:"10px 12px", color:COLORS.satisfied, fontWeight:600 }}>{p.satisfied}</td>
                <td style={{ padding:"10px 12px", color:COLORS.neutral,    fontWeight:600 }}>{p.neutral}</td>
                <td style={{ padding:"10px 12px", color:COLORS.dissatisfied, fontWeight:600 }}>{p.dissatisfied}</td>
                <td style={{ padding:"10px 12px", color:T.muted }}>{p.total}</td>
                <td style={{ padding:"10px 12px" }}>
                  <span style={{ fontSize:10, padding:"3px 9px", borderRadius:20, fontWeight:600,
                    background: selectedProduct===p.product ? `${T.brand}20` : T.dimmed,
                    color: selectedProduct===p.product ? T.brand : T.muted }}>
                    {selectedProduct===p.product ? "Selected ✓" : "View"}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* ── AI Semantic Analysis ── */}
      <div style={{ background:T.panel, border:`1px solid ${T.brand}44`, borderRadius:14, padding:22, marginBottom:18 }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
          <div style={{ display:"flex", alignItems:"center", gap:10 }}>
            <div style={{ width:3, height:18, background:T.brand, borderRadius:2 }} />
            <span style={{ fontSize:12, fontWeight:700, letterSpacing:"0.08em", textTransform:"uppercase", color:T.text }}>
              AI Semantic Analysis {selectedProduct ? `· ${selectedProduct}` : `· ${selectedCat}`}
            </span>
          </div>
          <button onClick={runSemanticAnalysis} disabled={loadingAI} style={{
            background: loadingAI ? T.dimmed : T.brand,
            border:"none", borderRadius:10, padding:"8px 18px",
            color:"#fff", fontFamily:"'Sora',sans-serif", fontSize:11,
            fontWeight:700, cursor: loadingAI ? "not-allowed" : "pointer",
          }}>
            {loadingAI ? "Analysing..." : "Run Claude Analysis ✦"}
          </button>
        </div>
        {aiInsight ? (
          <div style={{ fontSize:12.5, color:T.text, lineHeight:1.8, whiteSpace:"pre-line",
            background:T.dimmed, borderRadius:10, padding:16 }}>
            {aiInsight}
          </div>
        ) : (
          <div style={{ fontSize:12, color:T.muted, fontStyle:"italic" }}>
            Click "Run Claude Analysis" to get AI-powered insights on {selectedProduct || selectedCat} reviews.
          </div>
        )}
      </div>

      {/* ── Review table ── */}
      <div style={{ background:T.panel, border:`1px solid ${T.border}`, borderRadius:14, padding:22 }}>
        <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:16 }}>
          <div style={{ display:"flex", alignItems:"center", gap:10 }}>
            <div style={{ width:3, height:18, background:T.brand, borderRadius:2 }} />
            <span style={{ fontSize:12, fontWeight:700, letterSpacing:"0.08em", textTransform:"uppercase", color:T.text }}>
              Customer Reviews {selectedProduct ? `· ${selectedProduct}` : "· All Products"}
            </span>
          </div>
          <span style={{ fontSize:11, color:T.muted }}>{tableReviews.length} shown</span>
        </div>
        <table style={{ width:"100%", borderCollapse:"collapse" }}>
          <thead>
            <tr style={{ borderBottom:`1px solid ${T.border}` }}>
              {["Customer","Product","Rating","Sentiment","Review","Date","Verified"].map(h => (
                <th key={h} style={{ padding:"8px 12px", textAlign:"left", color:T.muted, fontSize:10, fontWeight:600 }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {tableReviews.map(r => (
              <tr key={r.id} style={{ borderBottom:`1px solid ${T.dimmed}` }}>
                <td style={{ padding:"10px 12px", fontWeight:600, color:T.text, fontSize:11 }}>{r.customer}</td>
                <td style={{ padding:"10px 12px", color:T.muted, fontSize:10 }}>{r.product}</td>
                <td style={{ padding:"10px 12px", color:T.brandAlt, fontWeight:700 }}>{"★".repeat(r.rating)}{"☆".repeat(5-r.rating)}</td>
                <td style={{ padding:"10px 12px" }}>
                  <span style={{ fontSize:10, padding:"3px 9px", borderRadius:20, fontWeight:600,
                    background: COLORS[r.sentiment]+"22", color: COLORS[r.sentiment] }}>
                    {r.sentiment}
                  </span>
                </td>
                <td style={{ padding:"10px 12px", color:T.text, fontSize:11, maxWidth:300 }}>{r.review}</td>
                <td style={{ padding:"10px 12px", color:T.muted, fontSize:10 }}>{r.date}</td>
                <td style={{ padding:"10px 12px", color: r.verified?COLORS.satisfied:T.muted, fontSize:11 }}>
                  {r.verified ? "✓ Yes" : "—"}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {tableReviews.length < (selectedProductData ? selectedProductData.reviews.length : FEEDBACK_DATA.filter(r=>r.category===selectedCat).length) && (
          <button onClick={() => setVisibleReviews(v => v+10)} style={{
            marginTop:14, background:T.dimmed, border:`1px solid ${T.border}`,
            borderRadius:8, padding:"8px 20px", color:T.muted, cursor:"pointer",
            fontFamily:"'Sora',sans-serif", fontSize:11, fontWeight:600, width:"100%",
          }}>
            Load More Reviews
          </button>
        )}
      </div>
    </div>
  );
}