// Seeded PRNG — deterministic, same values every session start
// Only the live ticker uses Math.random() for micro-jitter
let _seed = 42;
function seededRand(a, b) {
  _seed = (_seed * 1664525 + 1013904223) & 0xffffffff;
  const t = (_seed >>> 0) / 0xffffffff;
  return a + t * (b - a);
}
function seededRandInt(a, b) { return Math.floor(seededRand(a, b)); }

// Keep rand/randInt/pick as public exports but now seeded
export const rand    = (a, b) => seededRand(a, b);
export const randInt = (a, b) => seededRandInt(a, b);
export const pick    = (arr) => arr[seededRandInt(0, arr.length)];

// Call this to reset seed before any data generation
export function resetSeed(s = 42) { _seed = s; }

// ── Realistic retail KPIs ──
export function genKPIs(dateRange = 30) {
  const gmv           = rand(8_200_000, 12_500_000);
  const orders        = randInt(14000, 22000);
  const aov           = gmv / orders;                          // Avg Order Value
  const sessions      = randInt(180000, 310000);
  const convRate      = (orders / sessions) * 100;
  const cartAbandRate = rand(62, 79);                          // industry avg 70%
  const returnRate    = rand(8, 18);
  const newCust       = randInt(3200, 7800);
  const repeatCust    = randInt(6000, 14000);
  const ltv           = rand(2800, 5400);                      // Customer LTV ₹
  const invTurnover   = rand(4.2, 9.1);                        // times/year
  const netRevenue    = gmv * (1 - returnRate / 100) * 0.72;  // after returns + COGS

  return { gmv, orders, aov, sessions, convRate, cartAbandRate, returnRate, newCust, repeatCust, ltv, invTurnover, netRevenue };
}

// forexRate: real USD/INR from ExchangeRate-API
// gdpGrowth: real India GDP % from World Bank
// Both params default to constants so it still works before APIs load
export function genGMVSeries(days = 90, forexRate = 83.5, gdpGrowth = 6.8) {
  resetSeed(42); // deterministic — same shape every call with same params
  // Scale base GMV to real forex rate (stronger rupee = lower INR GMV base)
  let base = seededRand(280000, 340000) * (forexRate / 83.5);
  const weekend_boost = [1.0, 0.88, 0.85, 0.87, 0.92, 1.18, 1.35];
  // Real India festive calendar: Diwali ~day 45-47, Republic Day ~day 78
  const FESTIVAL_DAYS = new Set([14, 15, 45, 46, 47, 78, 79]);
  // GDP growth anchors the trend: 6.8% GDP → ~9% e-retail growth (Redseer ratio)
  const annualGrowth = (gdpGrowth / 6.8) * 0.09;

  return Array.from({ length: days }, (_, i) => {
    const dow      = new Date(Date.now() - (days - i) * 86400000).getDay();
    const wkMult   = weekend_boost[dow];
    const trend    = 1 + (i / days) * annualGrowth;
    const festMult = FESTIVAL_DAYS.has(i) ? seededRand(1.6, 2.2) : 1;
    const noise    = seededRand(0.96, 1.05); // small deterministic jitter
    base           = Math.max(150000, Math.min(900000, base * noise * wkMult * trend * festMult));
    const date     = new Date(Date.now() - (days - i) * 86400000);
    return {
      date:   date.toLocaleDateString("en-IN", { day:"2-digit", month:"short" }),
      gmv:    Math.round(base),
      orders: Math.round(base / seededRand(480, 720)),
      returns:Math.round(base * seededRand(0.08, 0.16) / 500),
      rawDate: date,
    };
  });
}

