// ── Live USD→INR forex rate ──
export async function fetchForexRate() {
  try {
    const r = await fetch("https://open.er-api.com/v6/latest/USD");
    const d = await r.json();
    return { rate: d.rates?.INR ?? 83.5, source: "ExchangeRate-API ✓" };
  } catch {
    return { rate: 83.5, source: "fallback" };
  }
}

// ── India GDP growth + CPI inflation (World Bank) ──
export async function fetchIndiaMacro() {
  try {
    const [gdpR, cpiR] = await Promise.all([
      fetch("https://api.worldbank.org/v2/country/IN/indicator/NY.GDP.MKTP.KD.ZG?format=json&mrv=1"),
      fetch("https://api.worldbank.org/v2/country/IN/indicator/FP.CPI.TOTL.ZG?format=json&mrv=1"),
    ]);
    const gdpD = await gdpR.json();
    const cpiD = await cpiR.json();
    return {
      gdpGrowth: gdpD[1]?.[0]?.value ?? 6.8,
      gdpYear:   gdpD[1]?.[0]?.date  ?? "2023",
      inflation: cpiD[1]?.[0]?.value ?? 5.4,
      source: "World Bank ✓",
    };
  } catch {
    return { gdpGrowth: 6.8, gdpYear: "2023", inflation: 5.4, source: "fallback" };
  }
}

