// ── Lexicon-based sentiment engine (mirrors Python VADER / TextBlob logic) ──
const POS_WORDS = ["love","great","excellent","amazing","fantastic","perfect","best","good","happy",
  "satisfied","superb","outstanding","premium","wonderful","fast","quick","solid","recommended",
  "impressive","pleased","nice","beautiful","stylish","smooth","durable","worth","helpful","easy",
  "comfortable","genuine","effective","reliable","sturdy","clean","responsive"];
const NEG_WORDS = ["terrible","bad","worst","awful","horrible","poor","disappointed","damaged",
  "broken","fake","cheap","useless","waste","scam","defective","wrong","late","rude",
  "frustrating","disappointing","refund","return","complaint","glitchy","stopped","smell",
  "scratch","thin","missing","failed","slow","delayed","different","cheated","garbage","avoid"];
const INTENSIFIERS = ["very","extremely","absolutely","completely","totally","super","highly","much"];
const NEGATORS     = ["not","never","no","didn't","don't","wasn't","isn't","hardly","barely"];

export function analyzeSentiment(text) {
  const words = text.toLowerCase().replace(/[^a-z\s']/g, " ").split(/\s+/);
  let score = 0, posCount = 0, negCount = 0;
  const keywords = [];

  words.forEach((word, i) => {
    const prev = words[i - 1] || "";
    const prev2 = words[i - 2] || "";
    const isNegated = NEGATORS.includes(prev) || NEGATORS.includes(prev2);
    const intensity = INTENSIFIERS.includes(prev) ? 1.5 : 1.0;

    if (POS_WORDS.includes(word)) {
      score += isNegated ? -1.2 : 1.2 * intensity;
      isNegated ? negCount++ : posCount++;
      keywords.push({ word, type: isNegated ? "negated" : "positive" });
    }
    if (NEG_WORDS.includes(word)) {
      score += isNegated ? 0.8 : -1.5 * intensity;
      isNegated ? posCount++ : negCount++;
      keywords.push({ word, type: isNegated ? "negated" : "negative" });
    }
  });

  const normalized = Math.max(-1, Math.min(1, score / (words.length * 0.6)));
  let label, confidence;
  if      (normalized >  0.15) { label = "Positive"; confidence = Math.min(99, Math.round(60 + normalized * 38)); }
  else if (normalized < -0.15) { label = "Negative"; confidence = Math.min(99, Math.round(60 + Math.abs(normalized) * 38)); }
  else                         { label = "Neutral";  confidence = Math.round(55 + Math.abs(normalized) * 20); }

  // Aspect extraction
  const ASPECT_MAP = {
    delivery: ["delivery","shipping","arrived","fast","late","delayed","days"],
    quality:  ["quality","build","material","durable","cheap","broken","sturdy","solid"],
    packaging:["packaging","packed","box","torn","damaged","presentation"],
    price:    ["price","expensive","cheap","value","worth","cost","affordable","overpriced"],
    support:  ["support","customer","service","response","refund","helpful","rude"],
  };
  const aspects = {};
  Object.entries(ASPECT_MAP).forEach(([aspect, terms]) => {
    const found = terms.filter(t => text.toLowerCase().includes(t));
    if (found.length > 0) {
      const aspScore = found.reduce((s, t) => {
        const idx = text.toLowerCase().indexOf(t);
        const ctx = text.toLowerCase().slice(Math.max(0, idx - 15), idx + 15);
        const neg = NEGATORS.some(n => ctx.includes(n));
        const pos = POS_WORDS.some(p => ctx.includes(p));
        const bad = NEG_WORDS.some(n => ctx.includes(n));
        return s + (pos && !neg ? 1 : bad && !neg ? -1 : 0);
      }, 0);
      aspects[aspect] = { score: aspScore, terms: found };
    }
  });

  return { score: normalized, label, confidence, posCount, negCount, keywords: keywords.slice(0, 5), aspects };
}

// Run sentiment on the full dataset and aggregate stats
export function analyzeDataset(reviews) {
  const analyzed  = reviews.map(r => ({ ...r, sentiment: analyzeSentiment(r.text) }));
  const total     = analyzed.length;
  const positive  = analyzed.filter(r => r.sentiment.label === "Positive").length;
  const negative  = analyzed.filter(r => r.sentiment.label === "Negative").length;
  const neutral   = analyzed.filter(r => r.sentiment.label === "Neutral").length;
  const avgScore  = analyzed.reduce((s, r) => s + r.sentiment.score, 0) / total;
  const avgRating = analyzed.reduce((s, r) => s + r.rating, 0) / total;

  const byCategory = {};
  analyzed.forEach(r => {
    if (!byCategory[r.category]) byCategory[r.category] = { pos:0, neg:0, neu:0, total:0, sumScore:0 };
    byCategory[r.category][r.sentiment.label === "Positive" ? "pos" : r.sentiment.label === "Negative" ? "neg" : "neu"]++;
    byCategory[r.category].total++;
    byCategory[r.category].sumScore += r.sentiment.score;
  });

  const wordFreq = {};
  analyzed.forEach(r => {
    r.sentiment.keywords.forEach(k => {
      const key = `${k.type}:${k.word}`;
      wordFreq[key] = (wordFreq[key] || 0) + 1;
    });
  });
  const topKeywords = Object.entries(wordFreq)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 12)
    .map(([k, v]) => ({ word: k.split(":")[1], type: k.split(":")[0], count: v }));

  const aspectTotals = {};
  analyzed.forEach(r => {
    Object.entries(r.sentiment.aspects).forEach(([asp, data]) => {
      if (!aspectTotals[asp]) aspectTotals[asp] = { sum:0, count:0 };
      aspectTotals[asp].sum   += data.score;
      aspectTotals[asp].count += 1;
    });
  });

  return { analyzed, total, positive, negative, neutral, avgScore, avgRating, byCategory, topKeywords, aspectTotals };
}